#include <stdio.h>
#include <math.h>

// Function to calculate the distance between two points
double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

// Function to check if three points are collinear
int isCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
    return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
}

// Function to calculate the area of a triangle using Heron's formula
double heronsFormula(double side1, double side2, double side3) {
    double s = (side1 + side2 + side3) / 2.0;
    return sqrt(s * (s - side1) * (s - side2) * (s - side3));
}

int main() {
    // Read coordinates of 4 points
    double x[4], y[4];
    printf("Enter the coordinates of 4 points: ");
    for (int i = 0; i < 4; i++) {
        scanf("%lf %lf", &x[i], &y[i]);
    }

    // Generate all 3-point combinations
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                double side1 = distance(x[i], y[i], x[j], y[j]);
                double side2 = distance(x[j], y[j], x[k], y[k]);
                double side3 = distance(x[k], y[k], x[i], y[i]);

                // Check if points are collinear
                if (isCollinear(x[i], y[i], x[j], y[j], x[k], y[k])) {
                    printf("Collinear: %lf, %lf, %lf\n", x[i], y[i], x[j]);
                    continue;
                }

                // Calculate area using Heron's formula
                double area = heronsFormula(side1, side2, side3);
                printf("Area of triangle (%.3lf, %.3lf), (%.3lf, %.3lf), (%.3lf, %.3lf): %.3lf\n", 
                       x[i], y[i], x[j], y[j], x[k], y[k], area);
            }
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

void generateRandomNumbers(int numbers[]) {
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }
}

void displayNumbers(int numbers[]) {
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("* ");
    }
    printf("\n");
}

void playGame() {
    int numbers[NUM_NUMBERS];
    generateRandomNumbers(numbers);

    int guessedPositions[NUM_NUMBERS] = {0};
    int score = 0;

    while (1) {
        displayNumbers(numbers);
        printf("Pick a position (1-%d): ", NUM_NUMBERS);
        int position;
        scanf("%d", &position);

        if (position < 1 || position > NUM_NUMBERS) {
            printf("Invalid position. Please try again.\n");
            continue;
        }

        guessedPositions[position - 1] = 1;

        printf("Guess even or odd (E/O): ");
        char guess;
        scanf(" %c", &guess);

        if ((numbers[position - 1] % 2 == 0 && guess == 'E') || 
            (numbers[position - 1] % 2 != 0 && guess == 'O')) {
            score += 5;
            printf("Correct! You win 5 points.\n");
            numbers[position - 1] = -1; // Mark as revealed
        } else {
            printf("Incorrect. Try again.\n");
        }

        int allRevealed = 1;
        for (int i = 0; i < NUM_NUMBERS; i++) {
            if (!guessedPositions[i]) {
                allRevealed = 0;
                break;
            }
        }

        if (allRevealed) {
            printf("All numbers revealed!\n");
            printf("Final score: %d\n", score);
            break;
        }
    }
}

int main() {
    srand(time(NULL));
    playGame();
    return 0;
}
